import React from 'react';
import './App.css';

function App() {
  return (
    <div className="app">
      <Header />
      <Hero />
      <WorkExperience />
      <TeamSection />
      <LogoSection />
      <FeaturedProjects />
      <Contact />
      <Footer />
    </div>
  );
}

function Header() {
  return (
    <header className="header">
      <div className="logo">𝓩</div>
      <nav>
        <ul>
          <li><a href="#home">Home</a></li>
          <li><a href="#about">About</a></li>
          <li><a href="#lab">Lab</a></li>
        </ul>
      </nav>
    </header>
  );
}

function Hero() {
  return (
    <section id="home" className="hero">
      <div className="hero-content">
        <div className="hero-text">
          <div className="greeting">
            <p>Hello! I Am <span className="accent">Sarthak Memon</span></p>
          </div>
          <div className="hero-title">
            <p>A Designer who</p>
            <h1>Judges a book <br />by its <span className="accent">Cover</span>...</h1>
            <p className="subtext">because if the cover doesn't impress you, what else will?</p>
          </div>
          <div className="role">
            <h2>I'm a Software Engineer.</h2>
            <p>Currently I'm a Software Engineer at <span className="company">@Company</span></p>
          </div>
          <div className="bio">
            <p>A self-taught UI/UX designer functioning in the industry for 3+ years now.</p>
            <p>I make meaningful and delightful digital products that create an equilibrium between user needs and business goals.</p>
          </div>
        </div>
        <div className="avatar">
          <img src="/api/placeholder/300/300" alt="Developer Avatar with Laptop" />
        </div>
      </div>
    </section>
  );
}

function WorkExperience() {
  const projects = [
    { id: 1, title: "CIB on the Mobile", icon: "A" },
    { id: 2, title: "CIB on the Mobile", icon: "🌙" },
    { id: 3, title: "CIB on the Mobile", icon: "🦄" },
    { id: 4, title: "CIB on the Mobile", icon: "🔮" }
  ];

  return (
    <section id="experience" className="work-experience">
      <h2>Work Experience</h2>
      <div className="projects-grid">
        {projects.map(project => (
          <div className="project-card" key={project.id}>
            <div className="project-icon">{project.icon}</div>
            <h3>{project.title}</h3>
            <button className="learn-more">LEARN MORE</button>
          </div>
        ))}
      </div>
    </section>
  );
}

function TeamSection() {
  return (
    <section className="team-section">
      <p>I'm currently looking to join a <span className="accent">cross-functional</span> team</p>
      <p>that values improving people's lives through accessible design.</p>
    </section>
  );
}

function LogoSection() {
  const logos = ["F", "⚛️", "C", "🌐", "📊", "🔷", "⚙️", "🔲", "📱", "🖌️"];

  return (
    <section className="logo-section">
      <div className="logo-grid">
        {logos.map((logo, index) => (
          <div className="logo-item" key={index}>
            {logo}
          </div>
        ))}
      </div>
    </section>
  );
}

function FeaturedProjects() {
  const featuredProjects = [
    {
      id: 1,
      title: "Example Project",
      description: "A web app for visualizing personalized Spotify data. View your top artists, top tracks, recently played tracks, and detailed audio information about each track. Create and save new playlists of recommended tracks based on your existing playlists and more."
    },
    {
      id: 2,
      title: "Example Project",
      description: "A web app for visualizing personalized Spotify data. View your top artists, top tracks, recently played tracks, and detailed audio information about each track. Create and save new playlists of recommended tracks based on your existing playlists and more."
    }
  ];

  return (
    <section className="featured-projects">
      {featuredProjects.map((project, index) => (
        <div className={`project ${index % 2 === 1 ? 'project-reverse' : ''}`} key={project.id}>
          <div className="project-info">
            <p className="label">Featured Project</p>
            <h3>{project.title}</h3>
            <div className="project-description">
              <p>{project.description}</p>
            </div>
            <div className="project-icons">
              <span>☀️</span>
              <span>🌙</span>
            </div>
          </div>
          <div className="project-image">
            <img src="/api/placeholder/400/300" alt="Project Screenshot" />
          </div>
        </div>
      ))}
    </section>
  );
}

function Contact() {
  return (
    <section id="contact" className="contact">
      <h2>Contact</h2>
      <p>I'm currently looking to join a cross-functional team that values improving people's lives through accessible design, or have a project in mind? Let's connect!</p>
      <p className="email">thefamousartist22@gmail.com</p>
      <div className="social-links">
        <a href="#" aria-label="Instagram">📷</a>
        <a href="#" aria-label="GitHub">🐙</a>
        <a href="#" aria-label="Google">🔍</a>
      </div>
    </section>
  );
}

function Footer() {
  return (
    <footer className="footer">
      <div className="brand-logo">𝓩</div>
    </footer>
  );
}

export default App;
